import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// A function that returns a localized string for the current locale.
///
/// Used for parameter labels and option descriptions.
typedef LocalizedText = String Function(AppLocalizations l10n);

/// The data type of a fractal parameter.
///
/// Determines how the parameter is rendered in the UI and how its
/// value is validated and stored.
enum FractalParamType {
  /// A floating-point number parameter.
  ///
  /// Rendered as a slider with continuous values.
  /// Value type: [double]
  float,

  /// An integer parameter.
  ///
  /// Rendered as a slider with discrete steps.
  /// Value type: [int]
  integer,

  /// A selection from a fixed set of options.
  ///
  /// Rendered as a dropdown or segmented control.
  /// Value type: depends on [FractalParamOption.value]
  enumeration,

  /// A boolean on/off parameter.
  ///
  /// Rendered as a switch or checkbox.
  /// Value type: [bool]
  boolean,
}

/// An option for an enumeration-type parameter.
///
/// Defines a single selectable value with its display label.
///
/// Example:
/// ```dart
/// FractalParamOption(
///   value: 0,
///   label: (l10n) => l10n.colorFire,
/// )
/// ```
class FractalParamOption {
  /// The underlying value for this option.
  ///
  /// This is what gets stored in the parameter map and passed to shaders.
  final Object value;

  /// Returns the localized display label for this option.
  final LocalizedText label;

  /// Creates a new parameter option.
  const FractalParamOption({
    required this.value,
    required this.label,
  });
}

/// Defines the schema for a configurable fractal parameter.
///
/// A [FractalParameter] describes how a single adjustable value should
/// behave: its valid range, step increment, default value, and UI
/// representation.
///
/// Parameters are defined per [FractalModule] and used to:
/// - Generate the controls UI automatically
/// - Validate user input
/// - Clamp values to valid ranges
/// - Store and restore presets
///
/// {@category Models}
///
/// Example:
/// ```dart
/// FractalParameter(
///   id: 'iterations',
///   label: (l10n) => l10n.paramIterations,
///   type: FractalParamType.integer,
///   min: 10,
///   max: 500,
///   step: 1,
///   defaultValue: 100,
/// )
/// ```
@immutable
class FractalParameter {
  /// Unique identifier for this parameter.
  ///
  /// Used as the key in parameter maps and for preset serialization.
  /// Should be a lowercase, camelCase string (e.g., 'iterations', 'colorScheme').
  final String id;

  /// Returns the localized display label for this parameter.
  ///
  /// Shown in the controls UI next to the input widget.
  final LocalizedText label;

  /// The data type of this parameter.
  ///
  /// Determines the UI widget and value handling.
  final FractalParamType type;

  /// The minimum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration] and [FractalParamType.boolean],
  /// this is typically 0.
  final double min;

  /// The maximum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration], this should match `options.length - 1`.
  final double max;

  /// The step increment for slider-based inputs.
  ///
  /// For integers, use 1.0. For floats, use an appropriate precision
  /// (e.g., 0.1 or 0.01).
  final double step;

  /// The initial value when no preset is applied.
  ///
  /// Must be within the [min]/[max] range and compatible with [type].
  final Object defaultValue;

  /// Available options for enumeration-type parameters.
  ///
  /// Only used when [type] is [FractalParamType.enumeration].
  /// Empty for other types.
  final List<FractalParamOption> options;

  /// Creates a new [FractalParameter] with the specified schema.
  ///
  /// For enumeration types, ensure [options] is populated with
  /// all valid choices.
  const FractalParameter({
    required this.id,
    required this.label,
    required this.type,
    required this.min,
    required this.max,
    required this.step,
    required this.defaultValue,
    this.options = const [],
  });
}

import 'package:equatable/equatable.dart';
import 'package:vector_math/vector_math.dart';

/// Represents the complete rendering parameters for a fractal.
///
/// This class encapsulates all configurable options that affect how a fractal
/// is rendered, including mathematical parameters (power, iterations, bailout),
/// visual settings (color scheme, zoom), and spatial transformations (rotation).
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final params = FractalParams(
///   power: 8.0,
///   iterations: 100,
///   zoom: 2.0,
///   rotation: Vector3(0.5, 0.3, 0.0),
///   mousePos: Vector2.zero(),
/// );
/// ```
class FractalParams extends Equatable {
  /// The mathematical power used in fractal calculations.
  ///
  /// Higher values create more intricate patterns. For Mandelbulb fractals,
  /// values of 8 produce the classic shape, while lower or higher values
  /// create interesting variations.
  ///
  /// Typical range: 2.0 to 12.0
  final double power;

  /// The maximum number of iterations for escape-time calculations.
  ///
  /// Higher iteration counts reveal more detail but require more computation.
  /// Values between 50-200 are typical for interactive rendering.
  final int iterations;

  /// The escape radius threshold for fractal calculations.
  ///
  /// Points that exceed this distance from the origin are considered to have
  /// escaped. Lower values create sharper boundaries.
  ///
  /// Typical range: 1.0 to 4.0
  final double bailout;

  /// The current zoom/magnification level.
  ///
  /// Values greater than 1.0 zoom in, values less than 1.0 zoom out.
  /// Range is typically clamped to 0.1x - 10x.
  final double zoom;

  /// The 3D rotation angles for the fractal view.
  ///
  /// Used for 3D fractals (like Mandelbulb) to control camera orientation.
  /// Each component represents rotation around the X, Y, and Z axes respectively.
  final Vector3 rotation;

  /// The active color scheme index.
  ///
  /// Maps to [AppColorScheme] enum values:
  /// - 0: Fire
  /// - 1: Ocean
  /// - 2: Psychedelic
  /// - 3: Grayscale
  final int colorScheme;

  /// The current mouse/touch position in normalized coordinates.
  ///
  /// Used for interactive effects where the fractal responds to pointer position.
  final Vector2 mousePos;

  /// The type of fractal being rendered.
  ///
  /// Determines which algorithm is used for fractal generation.
  final FractalType fractalType;

  /// Creates a new [FractalParams] instance with the specified values.
  ///
  /// The [rotation] and [mousePos] vectors are required as they have no
  /// sensible universal default.
  const FractalParams({
    this.power = 8.0,
    this.iterations = 50,
    this.bailout = 2.0,
    this.zoom = 1.0,
    required this.rotation,
    this.colorScheme = 0,
    required this.mousePos,
    this.fractalType = FractalType.mandelbulb,
  });

  /// Creates a [FractalParams] with sensible default values.
  ///
  /// Useful for initialization when no specific parameters are needed.
  FractalParams.withDefaults()
      : power = 8.0,
        iterations = 50,
        bailout = 2.0,
        zoom = 1.0,
        rotation = Vector3(0.0, 0.0, 0.0),
        colorScheme = 0,
        mousePos = Vector2(0.0, 0.0),
        fractalType = FractalType.mandelbulb;

  /// Creates a copy of this [FractalParams] with the given fields replaced.
  ///
  /// All parameters are optional; unspecified parameters retain their
  /// original values.
  FractalParams copyWith({
    double? power,
    int? iterations,
    double? bailout,
    double? zoom,
    Vector3? rotation,
    int? colorScheme,
    Vector2? mousePos,
    FractalType? fractalType,
  }) {
    return FractalParams(
      power: power ?? this.power,
      iterations: iterations ?? this.iterations,
      bailout: bailout ?? this.bailout,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? this.rotation,
      colorScheme: colorScheme ?? this.colorScheme,
      mousePos: mousePos ?? this.mousePos,
      fractalType: fractalType ?? this.fractalType,
    );
  }

  @override
  List<Object?> get props => [
        power,
        iterations,
        bailout,
        zoom,
        rotation,
        colorScheme,
        mousePos,
        fractalType,
      ];
}

/// Available color schemes for fractal rendering.
///
/// Each scheme provides a distinct visual aesthetic for the fractal output.
enum AppColorScheme {
  /// Warm orange-red-yellow gradient, reminiscent of flames.
  fire,

  /// Cool blue-teal gradient, evoking underwater themes.
  ocean,

  /// Vibrant multi-color gradient with high saturation.
  psychedelic,

  /// Black-to-white gradient for a classic mathematical look.
  grayscale;
}

/// Types of fractals available for rendering.
///
/// Each type uses a different mathematical algorithm to generate
/// its characteristic patterns.
enum FractalType {
  /// 3D extension of the Mandelbrot set.
  ///
  /// Creates a bulbous, organic-looking 3D shape through
  /// spherical coordinate mapping.
  mandelbulb,

  /// Box-folding fractal with recursive transformations.
  ///
  /// Creates geometric, box-like structures with infinite detail.
  mandelbox,

  /// Complex-number iteration fractal.
  ///
  /// Uses a constant complex parameter to create varied 2D patterns.
  julia,

  /// Recursive tetrahedron subdivision.
  ///
  /// A 3D fractal created by iteratively removing tetrahedra
  /// from a larger tetrahedron.
  sierpinski;
}

import 'package:flutter_fractals/core/models/fractal_params.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  test('FractalParams equality includes fractalType', () {
    final a = FractalParams(
      rotation: Vector3.zero(),
      mousePos: Vector2.zero(),
      fractalType: FractalType.mandelbulb,
    );
    final b = a.copyWith(fractalType: FractalType.julia);

    expect(a, isNot(equals(b)));
  });
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  test('FractalController clamps boolean params: non-bool -> false (table-driven)', () {
    final boolModule = FractalModule(
      id: 'bool-module',
      displayName: (_) => 'Bool',
      dimension: FractalDimension.twoD,
      shaderAsset: 'shaders/unused.frag',
      parameters: [
        FractalParameter(
          id: 'flag',
          label: (_) => 'Flag',
          type: FractalParamType.boolean,
          min: 0,
          max: 1,
          step: 1,
          defaultValue: true,
        ),
      ],
      defaultPreset: FractalPreset(
        id: 'bool-default',
        moduleId: 'bool-module',
        name: 'Default',
        params: const {'flag': true},
        view: FractalViewState.initial(),
        createdAt: DateTime(2026, 1, 1),
        isBuiltIn: true,
      ),
      builtInPresets: const [],
      setUniforms: (_, __, ___, ____) {},
    );

    final registry = ModuleRegistry();
    // Ensure our module is selected by default.
    registry.modules.insert(0, boolModule);

    final controller = FractalController(registry);
    expect(controller.module.id, 'bool-module');

    final cases = <({Object input, bool expected})>[
      (input: true, expected: true),
      (input: false, expected: false),
      (input: 1, expected: false),
      (input: 'true', expected: false),
    ];

    for (final c in cases) {
      controller.updateParam('flag', c.input);
      expect(
        controller.params['flag'],
        c.expected,
        reason: 'input=${c.input}',
      );
    }
  });
}

import 'dart:async';
import 'dart:math';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/services/test_logger.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_view_input_bounds.dart';
import 'package:flutter_fractals/core/services/runtime_mode_service.dart';
import 'package:vector_math/vector_math.dart';

/// Manages the state of fractal rendering and user interactions.
///
/// [FractalController] is the central state manager for the fractal viewer.
/// It handles:
/// - **Module selection**: Switching between fractal types
/// - **Parameter updates**: Modifying fractal settings with validation
/// - **View transformations**: Pan, zoom, and rotation
/// - **Preset management**: Applying and randomizing configurations
///
/// This controller uses [ChangeNotifier] for reactive updates and is
/// typically provided via the Provider package.
///
/// {@category State Management}
///
/// Example usage:
/// ```dart
/// final controller = FractalController(registry);
///
/// // Switch fractal type
/// controller.selectModule(registry.byId('julia'));
///
/// // Update a parameter
/// controller.updateParam('iterations', 150);
///
/// // Apply a preset
/// controller.applyPreset(myPreset);
///
/// // Reset to defaults
/// controller.resetSession();
/// ```
class FractalController extends ChangeNotifier {
  static const bool _adaptiveIterationsEnabled = bool.fromEnvironment(
    'ADAPTIVE_ITERATIONS',
    defaultValue: true,
  );
  static const int _adaptiveIterationsMinStep = 8;
  static const double _adaptiveZoomEpsilon = 1.01;

  // Test mode detection - skip timer-based animations in automated tests.
  bool get _isTest => RuntimeModeService.isAutomatedTest;

  /// The module registry containing all available fractal types.
  final ModuleRegistry registry;

  final TestLogger? _logger;
  late FractalModule _module;
  Map<String, Object> _params = {};
  FractalViewState _view = FractalViewState.initial();
  bool _transparentBackground = false;
  bool _rotationLocked = false;
  bool _glowEnabled = false;
  double _glowSigma = 1.0; // blur radius multiplier: 1.0 = standard
  double _glowIntensity = 0.35; // opacity of glow layer

  // Animation state
  bool _isMorphing = false;
  double _morphProgress = 1.0;
  String? _previousModuleId;
  Timer? _morphTimer;
  bool _isCelebrating = false;
  Timer? _celebrationTimer;

  // Interesting spot tracking for celebrations
  int _consecutiveInterestingSpots = 0;
  DateTime? _lastInterestingSpotTime;
  final _celebrationController = StreamController<void>.broadcast();
  double _lastAdaptiveZoom = 1.0;

  /// Creates a new [FractalController] with the given [registry].
  ///
  /// Optionally accepts a [logger] for test instrumentation.
  /// Initializes with the first module in the registry.
  FractalController(this.registry, {TestLogger? logger}) : _logger = logger {
    _module = registry.modules.first;
    _applyPreset(_module.defaultPreset);
    _lastAdaptiveZoom = _view.zoom;
  }

  /// Whether a module morph transition is in progress.
  bool get isMorphing => _isMorphing;

  /// Progress of the current morph transition (0.0 to 1.0).
  double get morphProgress => _morphProgress;

  /// The previous module ID during a morph transition.
  String? get previousModuleId => _previousModuleId;

  /// Whether a celebration effect should be shown.
  bool get isCelebrating => _isCelebrating;

  /// Stream that emits when a celebration should be triggered.
  Stream<void> get onCelebration => _celebrationController.stream;

  /// The currently selected fractal module.
  ///
  /// Determines which fractal type is being rendered and
  /// what parameters are available.
  FractalModule get module => _module;

  /// Current parameter values keyed by parameter ID.
  ///
  /// These are passed to the shader each frame via [FractalRenderState].
  Map<String, Object> get params => _params;

  /// Current view state (pan, zoom, rotation).
  ///
  /// Updated by gesture handlers and preset application.
  FractalViewState get view => _view;

  /// Whether the fractal should render with a transparent background.
  ///
  /// Used for transparent PNG export.
  bool get transparentBackground => _transparentBackground;

  /// Whether gesture-based rotation is locked.
  bool get rotationLocked => _rotationLocked;

  bool get glowEnabled => _glowEnabled;
  double get glowSigma => _glowSigma;
  double get glowIntensity => _glowIntensity;

  // Kaleidoscope state
  bool _kaleidoscopeEnabled = false;
  int _kaleidoscopeSectors = 8;
  bool _kaleidoscopeMirror = true;
  double _kaleidoscopeRotation = 0.0;
  int _kaleidoscopeMirrorMode =
      0; // 0=alternado, 1=doble, 2=triple, 3=sin espejo

  bool get kaleidoscopeEnabled => _kaleidoscopeEnabled;
  int get kaleidoscopeSectors => _kaleidoscopeSectors;
  bool get kaleidoscopeMirror => _kaleidoscopeMirror;
  double get kaleidoscopeRotation => _kaleidoscopeRotation;
  int get kaleidoscopeMirrorMode => _kaleidoscopeMirrorMode;

  void setKaleidoscopeEnabled(bool enabled) {
    // Force enabled for kaleidoscope modules
    if (_module.id.contains('kaleidoscope')) {
      enabled = true;
    }
    if (_kaleidoscopeEnabled != enabled) {
      _kaleidoscopeEnabled = enabled;
      notifyListeners();
    }
  }

  void setKaleidoscopeSectors(int sectors) {
    final clamped = sectors.clamp(4, 16);
    if (_kaleidoscopeSectors != clamped) {
      _kaleidoscopeSectors = clamped;
      notifyListeners();
    }
  }

  void setKaleidoscopeMirror(bool mirror) {
    if (_kaleidoscopeMirror != mirror) {
      _kaleidoscopeMirror = mirror;
      notifyListeners();
    }
  }

  void setKaleidoscopeMirrorMode(int mode) {
    final clamped = mode.clamp(0, 3);
    if (_kaleidoscopeMirrorMode != clamped) {
      _kaleidoscopeMirrorMode = clamped;
      notifyListeners();
    }
  }

  void setKaleidoscopeRotation(double rotation) {
    if (_kaleidoscopeRotation != rotation) {
      _kaleidoscopeRotation = rotation;
      notifyListeners();
    }
  }

  /// Switches to a different fractal module.
  ///
  /// The [module] must be a valid module from the registry.
  /// Applies the module's default preset after switching.
  /// Triggers a smooth morph transition animation.
  ///
  /// No-op if [module] is already the current module.
  void selectModule(FractalModule module, {bool animate = true}) {
    if (_module.id == module.id) {
      return;
    }

    final previousId = _module.id;
    _module = module;
    _applyPreset(module.defaultPreset);

    if (animate) {
      _startMorphTransition(previousId);
    }

    // Auto-enable kaleidoscope effect for these modules with specific defaults
    if (module.id.contains('kaleidoscope')) {
      _kaleidoscopeEnabled = true;
      _kaleidoscopeSectors = 16;
      _kaleidoscopeMirrorMode = 3; // "Sin" espejo
    }

    notifyListeners();
    _logChange('stateChange', 'moduleSwitch', 'Switched to ${module.id}');
  }

  /// Starts a morph transition animation between fractal types.
  void _startMorphTransition(String fromModuleId) {
    // Skip timer-based animations in test mode
    if (_isTest) {
      _morphProgress = 1.0;
      _isMorphing = false;
      return;
    }

    _previousModuleId = fromModuleId;
    _isMorphing = true;
    _morphProgress = 0.0;

    HapticFeedback.lightImpact();

    _morphTimer?.cancel();

    const duration = Duration(milliseconds: 600);
    const fps = 60;
    final steps = (duration.inMilliseconds / (1000 / fps)).round();
    var step = 0;

    _morphTimer = Timer.periodic(
      Duration(milliseconds: 1000 ~/ fps),
      (timer) {
        step++;
        // Use ease-out cubic curve
        final t = step / steps;
        _morphProgress = 1.0 - pow(1.0 - t, 3);
        notifyListeners();

        if (step >= steps) {
          timer.cancel();
          _morphProgress = 1.0;
          _isMorphing = false;
          _previousModuleId = null;
          notifyListeners();
        }
      },

